var logger4 = createLogger("auth");
function register(username, password) {
  const db2 = getDb();
  const existing = db2.prepare("SELECT id FROM users WHERE username = ?").get(username);
  if (existing) {
    throw new HttpError(409, "\u7528\u6237\u540D\u5DF2\u88AB\u6CE8\u518C");
  }
  const passwordHash = bcryptjs_default.hashSync(password, bcryptjs_default.genSaltSync(10));
  const stmt = db2.prepare("INSERT INTO users (username, password_hash) VALUES (?, ?)");
  const result = stmt.run(username, passwordHash);
  const userId = Number(result.lastInsertRowid);
  const token = generateToken(userId, username);
  logger4.info(`[\u5BA1\u8BA1] \u7528\u6237 ${username} \u6267\u884C\u4E86 \u6CE8\u518C \u64CD\u4F5C`);
  return { token, user: { id: userId, username } };
}
function login(username, password) {
  const db2 = getDb();
  const user = db2.prepare("SELECT id, username, password_hash FROM users WHERE username = ?").get(username);
  if (!user || !bcryptjs_default.compareSync(password, user.password_hash)) {
    throw new HttpError(401, "\u7528\u6237\u540D\u6216\u5BC6\u7801\u9519\u8BEF");
  }
  const token = generateToken(user.id, user.username);
  logger4.info(`[\u5BA1\u8BA1] \u7528\u6237 ${user.username} \u6267\u884C\u4E86 \u767B\u5F55 \u64CD\u4F5C`);
  return { token, user: { id: user.id, username: user.username } };
}

