// dist/api/auth/auth.routes.js
async function authRoutes(app) {
  app.get("/bootstrap", async (_request, reply) => {
    const db2 = getDb();
    let userId;
    let username;
    const existing = db2.prepare("SELECT id, username FROM users WHERE id = 1").get();
    if (existing) {
      userId = existing.id;
      username = existing.username;
    } else {
      const passwordHash = bcryptjs_default.hashSync("default", bcryptjs_default.genSaltSync(10));
      db2.prepare("INSERT OR IGNORE INTO users (id, username, password_hash) VALUES (1, ?, ?)").run("default", passwordHash);
      userId = 1;
      username = "default";
    }
    const token = generateToken(userId, username);
    return reply.send({ token, user: { id: userId, username } });
  });
  app.post("/register", async (request, reply) => {
    const parsed = registerSchema.safeParse(request.body);
    if (!parsed.success) {
      return reply.status(400).send(errorResponse("VALIDATION_ERROR", parsed.error.issues[0]?.message ?? "\u8BF7\u6C42\u53C2\u6570\u65E0\u6548"));
    }
    const { username, password } = parsed.data;
    try {
      const result = register(username, password);
      return reply.send(result);
    } catch (err) {
      if (err instanceof HttpError) {
        return reply.status(err.statusCode).send({ error: err.message });
      }
      return reply.status(500).send({ error: err instanceof Error ? err.message : "\u6CE8\u518C\u5931\u8D25" });
    }
  });
  app.post("/login", async (request, reply) => {
    const parsed = loginSchema.safeParse(request.body);
    if (!parsed.success) {
      return reply.status(400).send(errorResponse("VALIDATION_ERROR", parsed.error.issues[0]?.message ?? "\u8BF7\u6C42\u53C2\u6570\u65E0\u6548"));
    }
    const { username, password } = parsed.data;
    try {
      const result = login(username, password);
      return reply.send(result);
    } catch (err) {
      if (err instanceof HttpError) {
        return reply.status(err.statusCode).send({ error: err.message });
      }
      return reply.status(500).send({ error: err instanceof Error ? err.message : "\u767B\u5F55\u5931\u8D25" });
    }
  });
}

