function findByUserId(userId) {
  const db2 = getDb();
  const rows = db2.prepare("SELECT id, user_id, title, is_archived, created_at, updated_at FROM conversations WHERE user_id = ? ORDER BY updated_at DESC").all(userId);
  return rows.map((row) => rowToDict(row));
}
function create(userId, title) {
  const db2 = getDb();
  const result = db2.prepare("INSERT INTO conversations (user_id, title, is_archived, created_at, updated_at) VALUES (?, ?, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)").run(userId, title);
  const row = db2.prepare("SELECT id, user_id, title, is_archived, created_at, updated_at FROM conversations WHERE id = ?").get(result.lastInsertRowid);
  return rowToDict(row);
}
function update(id, userId, fields) {
  const db2 = getDb();
  const existing = db2.prepare("SELECT id FROM conversations WHERE id = ? AND user_id = ?").get(id, userId);
  if (!existing)
    return null;
  const updates = [];
  const params = [];
  if (fields.title !== void 0 && fields.title !== null) {
    updates.push("title = ?");
    params.push(fields.title);
  }
  if (fields.is_archived !== void 0 && fields.is_archived !== null) {
    updates.push("is_archived = ?");
    params.push(fields.is_archived);
  }
  updates.push("updated_at = CURRENT_TIMESTAMP");
  params.push(id);
  params.push(userId);
  db2.prepare(`UPDATE conversations SET ${updates.join(", ")} WHERE id = ? AND user_id = ?`).run(...params);
  const row = db2.prepare("SELECT id, user_id, title, is_archived, created_at, updated_at FROM conversations WHERE id = ?").get(id);
  return rowToDict(row);
}
function deleteWithMessages(id, userId) {
  const db2 = getDb();
  const existing = db2.prepare("SELECT id FROM conversations WHERE id = ? AND user_id = ?").get(id, userId);
  if (!existing)
    return false;
  const deleteTransaction = db2.transaction(() => {
    db2.prepare("DELETE FROM session_notes_state WHERE conversation_id = ?").run(id);
    db2.prepare("DELETE FROM messages WHERE conversation_id = ?").run(id);
    db2.prepare("DELETE FROM conversations WHERE id = ? AND user_id = ?").run(id, userId);
  });
  deleteTransaction();
  return true;
}

